// src/components/PatientsManager.js - With Detail View & Your Design
import React, { useState, useEffect } from 'react';
import { Users, Plus, Edit2, Trash2, Upload, X, Save, ArrowLeft, FileText } from 'lucide-react';

const PatientsManager = ({ token }) => {
  const [patients, setPatients] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingPatient, setEditingPatient] = useState(null);
  const [selectedPatient, setSelectedPatient] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    age: '',
    gender: 'Male',
    conditions: '',
    medications: ''
  });

  const API_BASE = 'http://localhost:8000/api';

  useEffect(() => {
    loadPatients();
  }, [token]);

  const loadPatients = async () => {
    try {
      const response = await fetch(`${API_BASE}/patients`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await response.json();
      
      // Ensure data is always an array
      setPatients(Array.isArray(data) ? data : []);
      console.log('Patients loaded:', data);
    } catch (error) {
      console.error('Failed to load patients:', error);
      setPatients([]);
    } finally {
      setLoading(false);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      // ✅ Convert comma-separated string to array
      const comorbiditiesArray = formData.conditions
        .split(',')
        .map(item => item.trim())
        .filter(item => item.length > 0);
      
      const medicationsArray = formData.medications
        .split(',')
        .map(item => item.trim())
        .filter(item => item.length > 0);
  
      const response = await fetch(`${API_BASE}/patients`, {
        method: 'POST',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name,
          age: parseInt(formData.age),
          gender: formData.gender,
          comorbidities: comorbiditiesArray,  // ✅ Send as array
          medications: medicationsArray       // ✅ Send as array
        })
      });
  
      if (response.ok) {
        await loadPatients();
        closeModal();
        alert('Patient created successfully!');
      } else {
        const error = await response.json();
        alert(`Failed to create patient: ${error.detail || 'Unknown error'}`);
      }
    } catch (error) {
      console.error('Failed to create patient:', error);
      alert('Failed to create patient. Check console for details.');
    }
  };
  

  const handleUpdate = async (e) => {
    e.preventDefault();
    try {
      // ✅ Convert comma-separated string to array
      const comorbiditiesArray = formData.conditions
        .split(',')
        .map(item => item.trim())
        .filter(item => item.length > 0);
      
      const medicationsArray = formData.medications
        .split(',')
        .map(item => item.trim())
        .filter(item => item.length > 0);
  
      const response = await fetch(`${API_BASE}/patients/${editingPatient.id}`, {
        method: 'PUT',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name,
          age: parseInt(formData.age),
          gender: formData.gender,
          comorbidities: comorbiditiesArray,  // ✅ Send as array
          medications: medicationsArray       // ✅ Send as array
        })
      });
  
      if (response.ok) {
        const updatedPatient = await response.json();
        await loadPatients();
        closeModal();
        setSelectedPatient(updatedPatient);
        alert('Patient updated successfully!');
      } else {
        const error = await response.json();
        alert(`Failed to update patient: ${error.detail || 'Unknown error'}`);
      }
    } catch (error) {
      console.error('Failed to update patient:', error);
      alert('Failed to update patient. Check console for details.');
    }
  };
  
  const handleDelete = async (id) => {
    if (!window.confirm('Are you sure you want to delete this patient?')) return;

    try {
      const response = await fetch(`${API_BASE}/patients/${id}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${token}` }
      });

      if (response.ok) {
        await loadPatients();
        setSelectedPatient(null);
      }
    } catch (error) {
      console.error('Failed to delete patient:', error);
    }
  };

  const handleUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('file', file);

    try {
      const response = await fetch(`${API_BASE}/patients/upload`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
        body: formData
      });

      if (response.ok) {
        await loadPatients();
        alert('Patient uploaded successfully!');
      }
    } catch (error) {
      console.error('Failed to upload patient:', error);
    }
  };

  const openEditModal = (patient) => {
    setEditingPatient(patient);
    setFormData({
      name: patient.name || '',
      age: patient.age || '',
      gender: patient.gender || 'Male',
      conditions: patient.comorbidities?.join(', ') || '',
      medications: patient.medications?.join(', ') || ''
    });
    setSelectedPatient(null); // Close detail view first
    setShowModal(true);
  };

  const openCreateModal = () => {
    setEditingPatient(null);
    setFormData({
      name: '',
      age: '',
      gender: 'Male',
      conditions: '',
      medications: ''
    });
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false);
    setEditingPatient(null);
  };

  const styles = {
    container: { color: 'white', padding: '40px' },
    header: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: '32px'
    },
    title: { 
      fontSize: '48px', 
      fontWeight: '800',
      background: 'linear-gradient(135deg, #22d3ee 0%, #3b82f6 100%)',
      WebkitBackgroundClip: 'text',
      WebkitTextFillColor: 'transparent'
    },
    buttonGroup: { display: 'flex', gap: '12px' },
    button: {
      padding: '14px 24px',
      background: 'linear-gradient(135deg, #22d3ee 0%, #3b82f6 100%)',
      border: 'none',
      borderRadius: '12px',
      color: 'white',
      fontSize: '14px',
      fontWeight: '600',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      transition: 'all 0.3s ease'
    },
    listCard: {
      background: 'rgba(30, 41, 59, 0.6)',
      backdropFilter: 'blur(10px)',
      padding: '24px',
      borderRadius: '16px',
      border: '1px solid rgba(100,116,139,0.3)',
      marginBottom: '16px',
      cursor: 'pointer',
      transition: 'all 0.3s ease'
    },
    detailCard: {
      background: 'rgba(30, 41, 59, 0.6)',
      backdropFilter: 'blur(10px)',
      padding: '32px',
      borderRadius: '24px',
      border: '1px solid rgba(100,116,139,0.3)',
    },
    modal: {
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      background: 'rgba(0,0,0,0.7)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      zIndex: 1000
    },
    modalContent: {
      background: 'rgba(30, 41, 59, 0.95)',
      padding: '32px',
      borderRadius: '24px',
      width: '500px',
      maxHeight: '80vh',
      overflowY: 'auto'
    },
    input: {
      width: '100%',
      padding: '12px',
      background: 'rgba(15, 23, 42, 0.5)',
      border: '1px solid rgba(100,116,139,0.3)',
      borderRadius: '8px',
      color: 'white',
      fontSize: '14px',
      marginBottom: '16px'
    },
    label: {
      display: 'block',
      color: '#cbd5e1',
      fontSize: '14px',
      fontWeight: '600',
      marginBottom: '8px'
    },
    infoSection: {
      marginBottom: '24px'
    },
    infoLabel: {
      fontSize: '12px',
      color: '#94a3b8',
      textTransform: 'uppercase',
      letterSpacing: '1px',
      marginBottom: '8px'
    },
    infoValue: {
      fontSize: '18px',
      color: 'white',
      fontWeight: '600'
    },
    badge: {
      display: 'inline-block',
      padding: '6px 12px',
      background: 'rgba(34, 211, 238, 0.2)',
      border: '1px solid rgba(34, 211, 238, 0.3)',
      borderRadius: '8px',
      fontSize: '12px',
      marginRight: '8px',
      marginBottom: '8px'
    }
  };

  if (loading) return <div style={styles.container}>Loading patients...</div>;

  // Detail View
  if (selectedPatient) {
    return (
      <div style={styles.container}>
        <button
          style={{ ...styles.button, marginBottom: '24px' }}
          onClick={() => setSelectedPatient(null)}
        >
          <ArrowLeft size={18} />
          Back to List
        </button>

        <div style={styles.detailCard}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '32px' }}>
            <div>
              <h1 style={{ fontSize: '36px', fontWeight: '800', marginBottom: '8px' }}>
                {selectedPatient.name || 'Unknown Patient'}
              </h1>
              <div style={{ color: '#94a3b8', fontSize: '16px' }}>
                MRN: {selectedPatient.mrn}
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button
                onClick={() => openEditModal(selectedPatient)}
                style={{
                  ...styles.button,
                  background: 'rgba(59, 130, 246, 0.2)',
                  border: '1px solid rgba(59, 130, 246, 0.3)'
                }}
              >
                <Edit2 size={18} />
                Edit
              </button>
              <button
                onClick={() => handleDelete(selectedPatient.id)}
                style={{
                  ...styles.button,
                  background: 'rgba(239, 68, 68, 0.2)',
                  border: '1px solid rgba(239, 68, 68, 0.3)'
                }}
              >
                <Trash2 size={18} />
                Delete
              </button>
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '24px', marginBottom: '32px' }}>
            <div style={styles.infoSection}>
              <div style={styles.infoLabel}>Age</div>
              <div style={styles.infoValue}>{selectedPatient.age || 'N/A'} years</div>
            </div>
            <div style={styles.infoSection}>
              <div style={styles.infoLabel}>Gender</div>
              <div style={styles.infoValue}>{selectedPatient.gender || 'N/A'}</div>
            </div>
            <div style={styles.infoSection}>
              <div style={styles.infoLabel}>Created</div>
              <div style={styles.infoValue}>
                {new Date(selectedPatient.created_at).toLocaleDateString()}
              </div>
            </div>
          </div>

          <div style={styles.infoSection}>
            <div style={styles.infoLabel}>Medical Conditions</div>
            {selectedPatient.comorbidities && selectedPatient.comorbidities.length > 0 ? (
              <div>
                {selectedPatient.comorbidities.map((cond, idx) => (
                  <span key={idx} style={styles.badge}>{cond}</span>
                ))}
              </div>
            ) : (
              <div style={{ color: '#94a3b8' }}>No conditions recorded</div>
            )}
          </div>

          <div style={styles.infoSection}>
            <div style={styles.infoLabel}>Current Medications</div>
            {selectedPatient.medications && selectedPatient.medications.length > 0 ? (
              <div>
                {selectedPatient.medications.map((med, idx) => (
                  <span key={idx} style={styles.badge}>{med}</span>
                ))}
              </div>
            ) : (
              <div style={{ color: '#94a3b8' }}>No medications recorded</div>
            )}
          </div>

          {selectedPatient.lab_values && Object.keys(selectedPatient.lab_values).length > 0 && (
            <div style={styles.infoSection}>
              <div style={styles.infoLabel}>Lab Values</div>
              <div style={{ 
                background: 'rgba(15, 23, 42, 0.5)', 
                padding: '16px', 
                borderRadius: '12px',
                fontFamily: 'monospace'
              }}>
                {Object.entries(selectedPatient.lab_values).map(([key, value]) => (
                  <div key={key} style={{ marginBottom: '8px' }}>
                    <span style={{ color: '#22d3ee' }}>{key}:</span> {value}
                  </div>
                ))}
              </div>
            </div>
          )}

<div style={{
  background: 'rgba(34, 211, 238, 0.1)',
  border: '1px solid rgba(34, 211, 238, 0.3)',
  borderRadius: '12px',
  padding: '16px',
  marginTop: '24px'
}}>
  <div style={{ fontSize: '14px', color: '#22d3ee', fontWeight: '600', marginBottom: '12px' }}>
    📋 ML-Generated Patient Profile
  </div>
  
  {/* ✅ Show extraction details */}
  <div style={{ fontSize: '14px', color: '#cbd5e1', lineHeight: '1.8' }}>
    {selectedPatient.pdf_url && (
      <div style={{ marginBottom: '12px', padding: '12px', background: 'rgba(34, 211, 238, 0.1)', borderRadius: '8px' }}>
        <strong style={{ color: '#22d3ee' }}>📄 Source:</strong> Extracted from uploaded PDF document
      </div>
    )}
    
    {selectedPatient.extracted_at && (
      <div style={{ marginBottom: '12px' }}>
        <strong>⏱️ Processed:</strong> {new Date(selectedPatient.extracted_at).toLocaleString()}
      </div>
    )}
    
    {/* Show what was extracted */}
    <div style={{ marginTop: '16px', padding: '16px', background: 'rgba(15, 23, 42, 0.5)', borderRadius: '8px' }}>
      <div style={{ fontSize: '13px', color: '#94a3b8', marginBottom: '12px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '1px' }}>
        🤖 Auto-Extracted Clinical Entities
      </div>
      
      <div style={{ display: 'grid', gap: '8px' }}>
        {selectedPatient.comorbidities && selectedPatient.comorbidities.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span><strong>{selectedPatient.comorbidities.length}</strong> medical conditions identified using BioBERT NER</span>
          </div>
        )}
        
        {selectedPatient.medications && selectedPatient.medications.length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span><strong>{selectedPatient.medications.length}</strong> medications extracted via pharmaceutical entity recognition</span>
          </div>
        )}
        
        {selectedPatient.lab_values && Object.keys(selectedPatient.lab_values).length > 0 && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span><strong>{Object.keys(selectedPatient.lab_values).length}</strong> lab values parsed using regex patterns</span>
          </div>
        )}
        
        {selectedPatient.age && selectedPatient.gender && (
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <span style={{ color: '#10b981', fontSize: '16px' }}>✓</span>
            <span>Demographics extracted: <strong>Age {selectedPatient.age}, {selectedPatient.gender}</strong></span>
          </div>
        )}
        
        {(!selectedPatient.comorbidities || selectedPatient.comorbidities.length === 0) &&
         (!selectedPatient.medications || selectedPatient.medications.length === 0) &&
         (!selectedPatient.lab_values || Object.keys(selectedPatient.lab_values).length === 0) && (
          <div style={{ color: '#94a3b8', fontStyle: 'italic' }}>
            Manually entered patient data (no PDF extraction)
          </div>
        )}
      </div>
    </div>
    
    <div style={{ marginTop: '12px', fontSize: '13px', fontStyle: 'italic', color: '#94a3b8' }}>
      This patient profile was {selectedPatient.pdf_url ? 'automatically extracted and ' : ''}structured using BioBERT NER models and semantic analysis. 
      Clinical entities have been categorized for semantic eligibility matching.
    </div>
  </div>
</div>

        </div>
      </div>
    );
  }

  // List View
  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>Patients</h1>
        <div style={styles.buttonGroup}>
          <label htmlFor="upload-patient" style={styles.button}>
            <Upload size={18} />
            Upload PDF
          </label>
          <input
            id="upload-patient"
            type="file"
            accept=".pdf"
            onChange={handleUpload}
            style={{ display: 'none' }}
          />
          <button style={styles.button} onClick={openCreateModal}>
            <Plus size={18} />
            Add Patient
          </button>
        </div>
      </div>

      {patients.length === 0 ? (
        <div style={styles.detailCard}>
          <div style={{ textAlign: 'center', padding: '40px' }}>
            <FileText size={64} style={{ opacity: 0.3, margin: '0 auto 16px' }} />
            <div style={{ fontSize: '20px', marginBottom: '8px' }}>No patients yet</div>
            <div style={{ color: '#94a3b8' }}>Upload a PDF or add your first patient manually!</div>
          </div>
        </div>
      ) : (
        patients.map((patient) => (
          <div
            key={patient.id}
            style={styles.listCard}
            onClick={() => setSelectedPatient(patient)}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = 'translateY(-4px)';
              e.currentTarget.style.boxShadow = '0 12px 24px rgba(0,0,0,0.3)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = 'none';
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <h3 style={{ fontSize: '20px', fontWeight: '700', marginBottom: '8px' }}>
                  {patient.name || 'Unknown'}
                </h3>
                <div style={{ color: '#94a3b8', fontSize: '14px' }}>
                  {patient.age || 'N/A'} years • {patient.gender || 'N/A'} • MRN: {patient.mrn}
                </div>
              </div>
              <div style={{
                padding: '8px 16px',
                background: 'rgba(34, 211, 238, 0.2)',
                borderRadius: '8px',
                fontSize: '12px',
                color: '#22d3ee',
                fontWeight: '600'
              }}>
                Click to view details →
              </div>
            </div>
          </div>
        ))
      )}

      {/* Modal for Add/Edit */}
      {showModal && (
        <div style={styles.modal} onClick={closeModal}>
          <div style={styles.modalContent} onClick={(e) => e.stopPropagation()}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '24px' }}>
              <h2 style={{ fontSize: '24px' }}>
                {editingPatient ? 'Edit Patient' : 'Add New Patient'}
              </h2>
              <button onClick={closeModal} style={{ background: 'none', border: 'none', color: 'white', cursor: 'pointer' }}>
                <X size={24} />
              </button>
            </div>

            <form onSubmit={editingPatient ? handleUpdate : handleCreate}>
              <label style={styles.label}>Name</label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                style={styles.input}
                required
              />

              <label style={styles.label}>Age</label>
              <input
                type="number"
                value={formData.age}
                onChange={(e) => setFormData({ ...formData, age: e.target.value })}
                style={styles.input}
                required
              />

              <label style={styles.label}>Gender</label>
              <select
                value={formData.gender}
                onChange={(e) => setFormData({ ...formData, gender: e.target.value })}
                style={styles.input}
              >
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>

              <label style={styles.label}>Conditions (comma-separated)</label>
              <input
                type="text"
                value={formData.conditions}
                onChange={(e) => setFormData({ ...formData, conditions: e.target.value })}
                style={styles.input}
                placeholder="e.g., Diabetes, Hypertension"
              />

              <label style={styles.label}>Medications (comma-separated)</label>
              <input
                type="text"
                value={formData.medications}
                onChange={(e) => setFormData({ ...formData, medications: e.target.value })}
                style={styles.input}
                placeholder="e.g., Metformin, Amlodipine"
              />

              <button type="submit" style={{ ...styles.button, width: '100%', justifyContent: 'center' }}>
                <Save size={18} />
                {editingPatient ? 'Update Patient' : 'Create Patient'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default PatientsManager;
